INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "무난하고 괜찮은 위스키다. 장단점이 섞여 있다. 특히 사과/배와 바닐라 향미가 정말 좋아서 자꾸만 향을 맡게 된다. 피트 향이 조금 강한 편이어서 아쉽다는 느낌이 든다. 다음에 기회가 되면 또 마셔보고 싶은 위스키다.", 3, NOW(), 74, 1);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "우수한 완성도의 위스키라고 평가한다. 사과/배와 곡물의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 모든 위스키 애호가에게 강력 추천하고 싶은 제품이다! 추천할 만한 가치가 있다.", 5, NOW(), 86, 1);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "우수한 완성도의 위스키라고 평가한다. 피트와 시트러스의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 모든 위스키 애호가에게 강력 추천하고 싶은 제품이다! 추천할 만한 가치가 있다.", 5, NOW(), 110, 1);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "흥미로운 위스키이지만 완성도는 아쉽다. 고민되는 부분이 있다. 조화로운 프로필이 특징이다. 특별한 매력을 느끼지는 못했지만 나쁘지는 않다. 추천할 만한 가치가 있다.", 3, NOW(), 131, 1);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 맛있어서 자꾸 마시고 싶은 위스키다! 조화로운 프로필이 특징이다. 위스키 애호가라면 반드시 한 번 마셔봐야 할 가치 있는 위스키다. 추천할 만한 가치가 있다.", 5, NOW(), 141, 1);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 맛있어서 자꾸 마시고 싶은 위스키다! 특히 시트러스와 꿀 향미가 정말 좋아서 자꾸만 향을 맡게 된다. 위스키 애호가라면 반드시 한 번 마셔봐야 할 가치 있는 위스키다. 정말 마음에 든다.", 5, NOW(), 185, 1);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 맛있어서 자꾸 마시고 싶은 위스키다! 특히 캐러멜와 꿀 향미가 정말 좋아서 자꾸만 향을 맡게 된다. 모든 위스키 애호가에게 강력 추천하고 싶은 제품이다! 정말 마음에 든다.", 5, NOW(), 210, 1);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 좋은 위스키다. 만족도가 정말 높다! 피트의 섬세하고 정교한 표현이 참으로 인상깊다. 다만 캐러멜 때문에 사람에 따라 호불호가 나뉠 수 있을 것 같다. 다시 한 번 마셔보고 싶은 생각이 드는 위스키다.", 4, NOW(), 253, 1);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 훌륭한 위스키다! 충동구매해도 후회 안 한다. 특히 곡물와 시트러스 향미가 정말 좋아서 자꾸만 향을 맡게 된다. 다시 한 번 마셔보고 싶은 생각이 드는 위스키다.", 4, NOW(), 274, 1);
