INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 맛있어서 자꾸 마시고 싶은 위스키다! 곡물의 섬세하고 정교한 표현이 참으로 인상깊다. 위스키 애호가라면 반드시 한 번 마셔봐야 할 가치 있는 위스키다. 추천할 만한 가치가 있다.", 5, NOW(), 174, 32);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 좋은 위스키다. 만족도가 정말 높다! 캐러멜 향이 매력적이어서 계속 생각난다. 한 번쯤은 꼭 마셔볼 만한 가치가 있다.", 4, NOW(), 256, 32);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "나쁘지 않은 위스키다. 충분히 마실 만하다. 곡물 향이 매력적이어서 계속 생각난다. 다음에 기회가 되면 또 마셔보고 싶은 위스키다.", 3, NOW(), 343, 32);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 훌륭한 위스키다! 충동구매해도 후회 안 한다. 바다/소금와 피트의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 다시 한 번 마셔보고 싶은 생각이 드는 위스키다.", 4, NOW(), 462, 32);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 최고의 경험이다! 이렇게 좋은 위스키는 처음이다. 건과일의 섬세하고 정교한 표현이 참으로 인상깊다. 모든 위스키 애호가에게 강력 추천하고 싶은 제품이다! 추천할 만한 가치가 있다.", 5, NOW(), 463, 32);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "나쁘지 않은 위스키다. 충분히 마실 만하다. 부드러운 식감 속에 진한 달콤함이 천천히 펼쳐지는 경험이 정말 좋다. 다음에 기회가 되면 또 마셔보고 싶은 위스키다.", 3, NOW(), 256, 33);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "무난하고 괜찮은 위스키다. 장단점이 섞여 있다. 초콜릿의 섬세하고 정교한 표현이 참으로 인상깊다. 담배 향이 조금 강한 편이어서 아쉽다는 느낌이 든다. 다음에 기회가 되면 또 마셔보고 싶은 위스키다.", 3, NOW(), 373, 33);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 최고의 경험이다! 이렇게 좋은 위스키는 처음이다. 숙성 오크와 시나몬의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 위스키 애호가라면 반드시 한 번 마셔봐야 할 가치 있는 위스키다.", 5, NOW(), 14, 34);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "평범한 수준의 위스키다. 특별한 매력이 부족하다. 바다/소금와 숙성 오크의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 특별한 매력을 느끼지는 못했지만 나쁘지는 않다.", 3, NOW(), 415, 34);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "무난하고 괜찮은 위스키다. 장단점이 섞여 있다. 건과일의 섬세하고 정교한 표현이 참으로 인상깊다. 다음에 기회가 되면 또 마셔보고 싶은 위스키다.", 3, NOW(), 435, 34);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 최고의 경험이다! 이렇게 좋은 위스키는 처음이다. 특히 숙성 오크와 시나몬 향미가 정말 좋아서 자꾸만 향을 맡게 된다. 충분히 좋은 선택이 될 것 같다.", 5, NOW(), 490, 34);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "흥미로운 위스키이지만 완성도는 아쉽다. 고민되는 부분이 있다. 지속력 있고 우아한 피니시가 전체 경험을 완성한다. 새 오크 향이 조금 강한 편이어서 아쉽다는 느낌이 든다. 특별한 매력을 느끼지는 못했지만 나쁘지는 않다.", 3, NOW(), 171, 35);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 최고의 경험이다! 이렇게 좋은 위스키는 처음이다. 꿀와 새 오크의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 모든 위스키 애호가에게 강력 추천하고 싶은 제품이다!", 5, NOW(), 173, 35);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "무난하고 괜찮은 위스키다. 장단점이 섞여 있다. 피트 향이 매력적이어서 계속 생각난다. 곡물 향이 조금 강한 편이어서 아쉽다는 느낌이 든다. 다음에 기회가 되면 또 마셔보고 싶은 위스키다.", 3, NOW(), 245, 35);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "충분히 만족스러운 위스키다. 전반적으로 잘 만들어졌다. 새 오크와 꿀의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 자주 마시고 싶은 일상형 위스키로서 강력히 추천한다.", 4, NOW(), 305, 35);
