INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 훌륭한 위스키다! 충동구매해도 후회 안 한다. 특히 꿀와 캐러멜 향미가 정말 좋아서 자꾸만 향을 맡게 된다. 다만 곡물 때문에 사람에 따라 호불호가 나뉠 수 있을 것 같다. 한 번쯤은 꼭 마셔볼 만한 가치가 있다.", 4, NOW(), 28, 55);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 좋은 위스키다. 만족도가 정말 높다! 특히 시트러스와 바닐라 향미가 정말 좋아서 자꾸만 향을 맡게 된다. 다시 한 번 마셔보고 싶은 생각이 드는 위스키다.", 4, NOW(), 51, 55);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "여러 가지 문제점이 보인다. 개선이 필요하다. 시나몬의 섬세하고 정교한 표현이 참으로 인상깊다. 아쉽게도 재구매할 마음이 생기지 않는다.", 2, NOW(), 83, 55);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 좋은 위스키다. 만족도가 정말 높다! 특히 캐러멜와 시나몬 향미가 정말 좋아서 자꾸만 향을 맡게 된다. 다시 한 번 마셔보고 싶은 생각이 드는 위스키다.", 4, NOW(), 139, 55);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 좋은 위스키다. 만족도가 정말 높다! 피트 향이 매력적이어서 계속 생각난다. 다만 캐러멜 때문에 사람에 따라 호불호가 나뉠 수 있을 것 같다. 한 번쯤은 꼭 마셔볼 만한 가치가 있다.", 4, NOW(), 148, 55);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 별로다. 추천하고 싶지 않다. 바닐라 향이 매력적이어서 계속 생각난다. 다만 피트 향이 꽤 강해서 입맛에 잘 맞지 않았다. 추천하고 싶지 않다.", 1, NOW(), 170, 55);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "나쁘지 않은 위스키다. 충분히 마실 만하다. 은은하고 향긋한 피트 향이 이 위스키의 정체성을 잘 드러낸다. 다음에 기회가 되면 또 마셔보고 싶은 위스키다.", 3, NOW(), 176, 55);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 좋은 위스키다. 만족도가 정말 높다! 바닐라 향이 매력적이어서 계속 생각난다. 한 번쯤은 꼭 마셔볼 만한 가치가 있다.", 4, NOW(), 207, 55);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "우수한 완성도의 위스키라고 평가한다. 캐러멜와 시나몬의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 모든 위스키 애호가에게 강력 추천하고 싶은 제품이다! 추천할 만한 가치가 있다.", 5, NOW(), 238, 55);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 최고의 경험이다! 이렇게 좋은 위스키는 처음이다. 피트의 섬세하고 정교한 표현이 참으로 인상깊다. 위스키 애호가라면 반드시 한 번 마셔봐야 할 가치 있는 위스키다. 추천할 만한 가치가 있다.", 5, NOW(), 248, 55);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "충분히 만족스러운 위스키다. 전반적으로 잘 만들어졌다. 꿀와 바닐라의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 자주 마시고 싶은 일상형 위스키로서 강력히 추천한다.", 4, NOW(), 250, 55);
