INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "무난하고 괜찮은 위스키다. 장단점이 섞여 있다. 우아한 달콤함과 풍성한 바디감의 조화로운 상호작용이 돋보인다. 곡물 향이 조금 강한 편이어서 아쉽다는 느낌이 든다. 다음에 기회가 되면 또 마셔보고 싶은 위스키다.", 3, NOW(), 104, 64);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "무난하고 괜찮은 위스키다. 장단점이 섞여 있다. 캐러멜 향이 매력적이어서 계속 생각난다. 다음에 기회가 되면 또 마셔보고 싶은 위스키다.", 3, NOW(), 121, 64);
