INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "여러 가지 문제점이 보인다. 개선이 필요하다. 이탄 향의 복합미와 깊이감이 매력적으로 표현된다. 약품향 특성이 개인의 미각 선호도와는 맞지 않아서 아쉽다. 아쉽게도 재구매할 마음이 생기지 않는다.", 2, NOW(), 184, 67);
