INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "흥미로운 위스키이지만 완성도는 아쉽다. 고민되는 부분이 있다. 곡물와 새 오크의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 특별한 매력을 느끼지는 못했지만 나쁘지는 않다.", 3, NOW(), 484, 71);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 좋은 위스키다. 만족도가 정말 높다! 특히 곡물와 바닐라 향미가 정말 좋아서 자꾸만 향을 맡게 된다. 한 번쯤은 꼭 마셔볼 만한 가치가 있다.", 4, NOW(), 496, 71);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "아쉬운 부분이 꽤 많다. 재평가가 필요해 보인다. 바닐라 향이 매력적이어서 계속 생각난다. 다만 담배 향이 꽤 강해서 입맛에 잘 맞지 않았다. 아쉽게도 재구매할 마음이 생기지 않는다.", 2, NOW(), 29, 72);
