INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "무난하고 괜찮은 위스키다. 장단점이 섞여 있다. 시나몬의 섬세하고 정교한 표현이 참으로 인상깊다. 다음에 기회가 되면 또 마셔보고 싶은 위스키다.", 3, NOW(), 59, 100);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "좋은 위스키이지만 몇 가지 개선 여지가 있어 보인다. 시나몬와 사과/배의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 자주 마시고 싶은 일상형 위스키로서 강력히 추천한다.", 4, NOW(), 18, 101);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "무난하고 괜찮은 위스키다. 장단점이 섞여 있다. 특히 시나몬와 바닐라 향미가 정말 좋아서 자꾸만 향을 맡게 된다. 다음에 기회가 되면 또 마셔보고 싶은 위스키다.", 3, NOW(), 29, 101);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "우수한 완성도의 위스키라고 평가한다. 시나몬와 캐러멜의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 모든 위스키 애호가에게 강력 추천하고 싶은 제품이다! 추천할 만한 가치가 있다.", 5, NOW(), 48, 101);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "우수한 완성도의 위스키라고 평가한다. 시나몬와 사과/배의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 모든 위스키 애호가에게 강력 추천하고 싶은 제품이다! 추천할 만한 가치가 있다.", 5, NOW(), 86, 101);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "충분히 만족스러운 위스키다. 전반적으로 잘 만들어졌다. 건과일의 섬세하고 정교한 표현이 참으로 인상깊다. 자주 마시고 싶은 일상형 위스키로서 강력히 추천한다. 추천할 만한 가치가 있다.", 4, NOW(), 104, 101);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "흥미로운 위스키이지만 완성도는 아쉽다. 고민되는 부분이 있다. 우아한 달콤함과 풍성한 바디감의 조화로운 상호작용이 돋보인다. 캐러멜 향이 조금 강한 편이어서 아쉽다는 느낌이 든다. 특별한 매력을 느끼지는 못했지만 나쁘지는 않다.", 3, NOW(), 118, 101);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 맛있어서 자꾸 마시고 싶은 위스키다! 건과일의 섬세하고 정교한 표현이 참으로 인상깊다. 위스키 애호가라면 반드시 한 번 마셔봐야 할 가치 있는 위스키다. 추천할 만한 가치가 있다.", 5, NOW(), 276, 101);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 최고의 경험이다! 이렇게 좋은 위스키는 처음이다. 시나몬와 건과일의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 위스키 애호가라면 반드시 한 번 마셔봐야 할 가치 있는 위스키다.", 5, NOW(), 294, 101);
