INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 별로다. 추천하고 싶지 않다. 균형 잡힌 맛의 조화가 매력적이다. 결국 내 취향과는 맞지 않는 위스키인 것 같다. 추천하고 싶지 않다.", 1, NOW(), 17, 115);
