INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "기대에 미치지 못했다. 여러 면에서 아쉽다. 부드러운 식감 속에 진한 달콤함이 천천히 펼쳐지는 경험이 정말 좋다. 다만 캐러멜 향이 꽤 강해서 입맛에 잘 맞지 않았다. 아쉽게도 재구매할 마음이 생기지 않는다.", 2, NOW(), 327, 116);
