INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "여러 가지 문제점이 보인다. 개선이 필요하다. 시나몬 향이 매력적이어서 계속 생각난다. 아쉽게도 재구매할 마음이 생기지 않는다.", 2, NOW(), 420, 123);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "우수한 완성도의 위스키라고 평가한다. 캐러멜와 사과/배의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 모든 위스키 애호가에게 강력 추천하고 싶은 제품이다! 추천할 만한 가치가 있다.", 5, NOW(), 106, 124);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "흥미로운 위스키이지만 완성도는 아쉽다. 고민되는 부분이 있다. 우아한 달콤함과 풍성한 바디감의 조화로운 상호작용이 돋보인다. 꿀 향이 조금 강한 편이어서 아쉽다는 느낌이 든다. 특별한 매력을 느끼지는 못했지만 나쁘지는 않다.", 3, NOW(), 171, 124);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "별로 마음에 들지 않는다. 기대와는 달랐다. 새 오크 향이 매력적이어서 계속 생각난다. 아쉽게도 재구매할 마음이 생기지 않는다.", 2, NOW(), 227, 124);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "여러 가지 문제점이 보인다. 개선이 필요하다. 우아한 달콤함과 풍성한 바디감의 조화로운 상호작용이 돋보인다. 바닐라 특성이 개인의 미각 선호도와는 맞지 않아서 아쉽다. 아쉽게도 재구매할 마음이 생기지 않는다.", 2, NOW(), 271, 124);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "좋은 위스키이지만 몇 가지 개선 여지가 있어 보인다. 바닐라와 새 오크의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 자주 마시고 싶은 일상형 위스키로서 강력히 추천한다.", 4, NOW(), 337, 124);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "무난하고 괜찮은 위스키다. 장단점이 섞여 있다. 부드러운 식감 속에 진한 달콤함이 천천히 펼쳐지는 경험이 정말 좋다. 캐러멜 향이 조금 강한 편이어서 아쉽다는 느낌이 든다. 다음에 기회가 되면 또 마셔보고 싶은 위스키다.", 3, NOW(), 376, 124);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 최고의 경험이다! 이렇게 좋은 위스키는 처음이다. 캐러멜의 섬세하고 정교한 표현이 참으로 인상깊다. 충분히 좋은 선택이 될 것 같다.", 5, NOW(), 417, 124);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 좋은 위스키다. 만족도가 정말 높다! 초콜릿의 섬세하고 정교한 표현이 참으로 인상깊다. 다시 한 번 마셔보고 싶은 생각이 드는 위스키다.", 4, NOW(), 174, 125);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 좋은 위스키다. 만족도가 정말 높다! 시나몬 향이 매력적이어서 계속 생각난다. 한 번쯤은 꼭 마셔볼 만한 가치가 있다.", 4, NOW(), 237, 125);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "평범한 수준의 위스키다. 특별한 매력이 부족하다. 특히 시나몬와 숙성 오크 향미가 정말 좋아서 자꾸만 향을 맡게 된다. 특별한 매력을 느끼지는 못했지만 나쁘지는 않다.", 3, NOW(), 270, 125);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "무난하고 괜찮은 위스키다. 장단점이 섞여 있다. 바닐라의 섬세하고 정교한 표현이 참으로 인상깊다. 다음에 기회가 되면 또 마셔보고 싶은 위스키다.", 3, NOW(), 341, 125);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 최고의 경험이다! 이렇게 좋은 위스키는 처음이다. 건과일와 초콜릿의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 위스키 애호가라면 반드시 한 번 마셔봐야 할 가치 있는 위스키다.", 5, NOW(), 463, 125);
