INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "기대에 미치지 못했다. 여러 면에서 아쉽다. 균형 잡힌 맛의 조화가 매력적이다. 다만 곡물 향이 꽤 강해서 입맛에 잘 맞지 않았다. 아쉽게도 재구매할 마음이 생기지 않는다.", 2, NOW(), 355, 136);
