INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 맛있어서 자꾸 마시고 싶은 위스키다! 꿀의 섬세하고 정교한 표현이 참으로 인상깊다. 모든 위스키 애호가에게 강력 추천하고 싶은 제품이다! 추천할 만한 가치가 있다.", 5, NOW(), 406, 138);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "평범한 수준의 위스키다. 특별한 매력이 부족하다. 시트러스와 곡물의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 꿀 향이 조금 강한 편이어서 아쉽다는 느낌이 든다. 특별한 매력을 느끼지는 못했지만 나쁘지는 않다.", 3, NOW(), 427, 138);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 최고의 경험이다! 이렇게 좋은 위스키는 처음이다. 조화로운 프로필이 특징이다. 위스키 애호가라면 반드시 한 번 마셔봐야 할 가치 있는 위스키다. 추천할 만한 가치가 있다.", 5, NOW(), 451, 138);
