INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "무난하고 괜찮은 위스키다. 장단점이 섞여 있다. 우아한 달콤함과 풍성한 바디감의 조화로운 상호작용이 돋보인다. 새 오크 향이 조금 강한 편이어서 아쉽다는 느낌이 든다. 다음에 기회가 되면 또 마셔보고 싶은 위스키다.", 3, NOW(), 364, 146);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "평범한 수준의 위스키다. 특별한 매력이 부족하다. 우아한 달콤함과 풍성한 바디감의 조화로운 상호작용이 돋보인다. 특별한 매력을 느끼지는 못했지만 나쁘지는 않다.", 3, NOW(), 20, 147);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "평범한 수준의 위스키다. 특별한 매력이 부족하다. 우아한 달콤함과 풍성한 바디감의 조화로운 상호작용이 돋보인다. 꿀 향이 조금 강한 편이어서 아쉽다는 느낌이 든다. 특별한 매력을 느끼지는 못했지만 나쁘지는 않다.", 3, NOW(), 23, 147);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "평범한 수준의 위스키다. 특별한 매력이 부족하다. 시나몬와 건과일의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 특별한 매력을 느끼지는 못했지만 나쁘지는 않다.", 3, NOW(), 71, 147);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 좋은 위스키다. 만족도가 정말 높다! 숙성 오크의 섬세하고 정교한 표현이 참으로 인상깊다. 다만 꿀 때문에 사람에 따라 호불호가 나뉠 수 있을 것 같다. 한 번쯤은 꼭 마셔볼 만한 가치가 있다.", 4, NOW(), 111, 147);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "좋은 위스키이지만 몇 가지 개선 여지가 있어 보인다. 숙성 오크와 시나몬의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 자주 마시고 싶은 일상형 위스키로서 강력히 추천한다.", 4, NOW(), 238, 147);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "여러 가지 문제점이 보인다. 개선이 필요하다. 우아한 달콤함과 풍성한 바디감의 조화로운 상호작용이 돋보인다. 아쉽게도 재구매할 마음이 생기지 않는다.", 2, NOW(), 239, 147);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 최고의 경험이다! 이렇게 좋은 위스키는 처음이다. 숙성 오크와 시나몬의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 위스키 애호가라면 반드시 한 번 마셔봐야 할 가치 있는 위스키다.", 5, NOW(), 394, 147);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "좋은 위스키이지만 몇 가지 개선 여지가 있어 보인다. 꿀와 숙성 오크의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 다시 한 번 마셔보고 싶은 생각이 드는 위스키다.", 4, NOW(), 499, 147);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "좋은 위스키이지만 몇 가지 개선 여지가 있어 보인다. 조화로운 프로필이 특징이다. 다시 한 번 마셔보고 싶은 생각이 드는 위스키다. 추천할 만한 가치가 있다.", 4, NOW(), 10, 149);
