INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "흥미로운 위스키이지만 완성도는 아쉽다. 고민되는 부분이 있다. 시나몬와 꽃향의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 특별한 매력을 느끼지는 못했지만 나쁘지는 않다.", 3, NOW(), 442, 150);
