INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "여러 가지 문제점이 보인다. 개선이 필요하다. 부드러운 식감 속에 진한 달콤함이 천천히 펼쳐지는 경험이 정말 좋다. 결국 내 취향과는 맞지 않는 위스키인 것 같다. 아쉽게도 재구매할 마음이 생기지 않는다.", 2, NOW(), 49, 155);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "무난하고 괜찮은 위스키다. 장단점이 섞여 있다. 새 오크의 섬세하고 정교한 표현이 참으로 인상깊다. 다음에 기회가 되면 또 마셔보고 싶은 위스키다. 추천할 만한 가치가 있다.", 3, NOW(), 101, 155);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "충분히 만족스러운 위스키다. 전반적으로 잘 만들어졌다. 시나몬와 캐러멜의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 자주 마시고 싶은 일상형 위스키로서 강력히 추천한다.", 4, NOW(), 133, 155);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 맛있어서 자꾸 마시고 싶은 위스키다! 바닐라와 캐러멜의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 모든 위스키 애호가에게 강력 추천하고 싶은 제품이다! 추천할 만한 가치가 있다.", 5, NOW(), 159, 155);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 맛있어서 자꾸 마시고 싶은 위스키다! 시나몬와 건과일의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 위스키 애호가라면 반드시 한 번 마셔봐야 할 가치 있는 위스키다.", 5, NOW(), 188, 155);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "여러 가지 문제점이 보인다. 개선이 필요하다. 우아한 달콤함과 풍성한 바디감의 조화로운 상호작용이 돋보인다. 아쉽게도 재구매할 마음이 생기지 않는다.", 2, NOW(), 239, 155);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "무난하고 괜찮은 위스키다. 장단점이 섞여 있다. 바닐라 향이 매력적이어서 계속 생각난다. 다음에 기회가 되면 또 마셔보고 싶은 위스키다.", 3, NOW(), 409, 155);
