INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 좋은 위스키다. 만족도가 정말 높다! 특히 초콜릿와 건과일 향미가 정말 좋아서 자꾸만 향을 맡게 된다. 다시 한 번 마셔보고 싶은 생각이 드는 위스키다.", 4, NOW(), 379, 164);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "좋은 위스키이지만 몇 가지 개선 여지가 있어 보인다. 시나몬와 숙성 오크의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 자주 마시고 싶은 일상형 위스키로서 강력히 추천한다.", 4, NOW(), 393, 164);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 최고의 경험이다! 이렇게 좋은 위스키는 처음이다. 시나몬와 숙성 오크의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 모든 위스키 애호가에게 강력 추천하고 싶은 제품이다!", 5, NOW(), 394, 164);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 훌륭한 위스키다! 충동구매해도 후회 안 한다. 캐러멜의 섬세하고 정교한 표현이 참으로 인상깊다. 다시 한 번 마셔보고 싶은 생각이 드는 위스키다.", 4, NOW(), 417, 164);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 맛있어서 자꾸 마시고 싶은 위스키다! 숙성 오크의 섬세하고 정교한 표현이 참으로 인상깊다. 위스키 애호가라면 반드시 한 번 마셔봐야 할 가치 있는 위스키다. 추천할 만한 가치가 있다.", 5, NOW(), 479, 164);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "무난하고 괜찮은 위스키다. 장단점이 섞여 있다. 특히 시나몬와 곡물 향미가 정말 좋아서 자꾸만 향을 맡게 된다. 꿀 향이 조금 강한 편이어서 아쉽다는 느낌이 든다. 다음에 기회가 되면 또 마셔보고 싶은 위스키다.", 3, NOW(), 99, 165);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "흥미로운 위스키이지만 완성도는 아쉽다. 고민되는 부분이 있다. 우아한 달콤함과 풍성한 바디감의 조화로운 상호작용이 돋보인다. 꿀 향이 조금 강한 편이어서 아쉽다는 느낌이 든다. 특별한 매력을 느끼지는 못했지만 나쁘지는 않다.", 3, NOW(), 180, 165);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "무난하고 괜찮은 위스키다. 장단점이 섞여 있다. 시나몬 향이 매력적이어서 계속 생각난다. 다음에 기회가 되면 또 마셔보고 싶은 위스키다.", 3, NOW(), 193, 165);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 좋은 위스키다. 만족도가 정말 높다! 견과류 향이 매력적이어서 계속 생각난다. 한 번쯤은 꼭 마셔볼 만한 가치가 있다.", 4, NOW(), 226, 165);
