INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "아쉬운 부분이 꽤 많다. 재평가가 필요해 보인다. 부드러운 식감 속에 진한 달콤함이 천천히 펼쳐지는 경험이 정말 좋다. 결국 내 취향과는 맞지 않는 위스키인 것 같다. 아쉽게도 재구매할 마음이 생기지 않는다.", 2, NOW(), 30, 166);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 최고의 경험이다! 이렇게 좋은 위스키는 처음이다. 시나몬의 섬세하고 정교한 표현이 참으로 인상깊다. 모든 위스키 애호가에게 강력 추천하고 싶은 제품이다! 추천할 만한 가치가 있다.", 5, NOW(), 32, 166);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "평범한 수준의 위스키다. 특별한 매력이 부족하다. 부드러운 식감 속에 진한 달콤함이 천천히 펼쳐지는 경험이 정말 좋다. 특별한 매력을 느끼지는 못했지만 나쁘지는 않다.", 3, NOW(), 43, 166);
