INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "여러 가지 문제점이 보인다. 개선이 필요하다. 시트러스 향이 매력적이어서 계속 생각난다. 아쉽게도 재구매할 마음이 생기지 않는다.", 2, NOW(), 334, 167);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 맛있어서 자꾸 마시고 싶은 위스키다! 시트러스와 바닐라의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 위스키 애호가라면 반드시 한 번 마셔봐야 할 가치 있는 위스키다.", 5, NOW(), 340, 167);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "여러 가지 문제점이 보인다. 개선이 필요하다. 균형 잡힌 맛의 조화가 매력적이다. 결국 내 취향과는 맞지 않는 위스키인 것 같다. 아쉽게도 재구매할 마음이 생기지 않는다.", 2, NOW(), 375, 167);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 맛있어서 자꾸 마시고 싶은 위스키다! 조화로운 프로필이 특징이다. 위스키 애호가라면 반드시 한 번 마셔봐야 할 가치 있는 위스키다. 추천할 만한 가치가 있다.", 5, NOW(), 383, 167);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "무난하고 괜찮은 위스키다. 장단점이 섞여 있다. 조화로운 프로필이 특징이다. 새 오크 향이 조금 강한 편이어서 아쉽다는 느낌이 든다. 다음에 기회가 되면 또 마셔보고 싶은 위스키다.", 3, NOW(), 386, 167);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "매우 잘 완성된 위스키다. 완성도 면에서 높은 수준이다. 특히 사과/배와 꿀 향미가 정말 좋아서 자꾸만 향을 맡게 된다. 자주 마시고 싶은 일상형 위스키로서 강력히 추천한다. 정말 마음에 든다.", 4, NOW(), 420, 167);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "충분히 만족스러운 위스키다. 전반적으로 잘 만들어졌다. 사과/배와 꿀의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 자주 마시고 싶은 일상형 위스키로서 강력히 추천한다.", 4, NOW(), 435, 167);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 맛있어서 자꾸 마시고 싶은 위스키다! 새 오크와 꿀의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 모든 위스키 애호가에게 강력 추천하고 싶은 제품이다! 추천할 만한 가치가 있다.", 5, NOW(), 450, 167);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 최고의 경험이다! 이렇게 좋은 위스키는 처음이다. 조화로운 프로필이 특징이다. 위스키 애호가라면 반드시 한 번 마셔봐야 할 가치 있는 위스키다. 추천할 만한 가치가 있다.", 5, NOW(), 454, 167);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "무난하고 괜찮은 위스키다. 장단점이 섞여 있다. 조화로운 프로필이 특징이다. 다음에 기회가 되면 또 마셔보고 싶은 위스키다.", 3, NOW(), 472, 167);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "충분히 만족스러운 위스키다. 전반적으로 잘 만들어졌다. 특히 사과/배와 곡물 향미가 정말 좋아서 자꾸만 향을 맡게 된다. 자주 마시고 싶은 일상형 위스키로서 강력히 추천한다. 정말 마음에 든다.", 4, NOW(), 476, 167);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 좋은 위스키다. 만족도가 정말 높다! 사과/배와 바닐라의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 다만 꿀 때문에 사람에 따라 호불호가 나뉠 수 있을 것 같다. 다시 한 번 마셔보고 싶은 생각이 드는 위스키다.", 4, NOW(), 481, 167);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "평범한 수준의 위스키다. 특별한 매력이 부족하다. 조화로운 프로필이 특징이다. 곡물 향이 조금 강한 편이어서 아쉽다는 느낌이 든다. 특별한 매력을 느끼지는 못했지만 나쁘지는 않다.", 3, NOW(), 482, 167);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "충분히 만족스러운 위스키다. 전반적으로 잘 만들어졌다. 특히 사과/배와 꿀 향미가 정말 좋아서 자꾸만 향을 맡게 된다. 자주 마시고 싶은 일상형 위스키로서 강력히 추천한다. 정말 마음에 든다.", 4, NOW(), 485, 167);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "우수한 완성도의 위스키라고 평가한다. 사과/배와 시나몬의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 모든 위스키 애호가에게 강력 추천하고 싶은 제품이다! 추천할 만한 가치가 있다.", 5, NOW(), 18, 168);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "좋은 위스키이지만 몇 가지 개선 여지가 있어 보인다. 초콜릿와 시나몬의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 자주 마시고 싶은 일상형 위스키로서 강력히 추천한다.", 4, NOW(), 69, 168);
