INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "무난하고 괜찮은 위스키다. 장단점이 섞여 있다. 정교한 향신료의 뉘앙스가 세련되게 표현된다. 곡물 향이 조금 강한 편이어서 아쉽다는 느낌이 든다. 다음에 기회가 되면 또 마셔보고 싶은 위스키다.", 3, NOW(), 104, 170);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 맛있어서 자꾸 마시고 싶은 위스키다! 후추의 섬세하고 정교한 표현이 참으로 인상깊다. 위스키 애호가라면 반드시 한 번 마셔봐야 할 가치 있는 위스키다. 추천할 만한 가치가 있다.", 5, NOW(), 109, 170);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "좋은 위스키이지만 몇 가지 개선 여지가 있어 보인다. 시트러스의 섬세하고 정교한 표현이 참으로 인상깊다. 자주 마시고 싶은 일상형 위스키로서 강력히 추천한다. 추천할 만한 가치가 있다.", 4, NOW(), 110, 170);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 좋은 위스키다. 만족도가 정말 높다! 시트러스의 섬세하고 정교한 표현이 참으로 인상깊다. 다만 캐러멜 때문에 사람에 따라 호불호가 나뉠 수 있을 것 같다. 한 번쯤은 꼭 마셔볼 만한 가치가 있다.", 4, NOW(), 111, 170);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 좋은 위스키다. 만족도가 정말 높다! 특히 시트러스와 새 오크 향미가 정말 좋아서 자꾸만 향을 맡게 된다. 다만 캐러멜 때문에 사람에 따라 호불호가 나뉠 수 있을 것 같다. 한 번쯤은 꼭 마셔볼 만한 가치가 있다.", 4, NOW(), 116, 170);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "충분히 만족스러운 위스키다. 전반적으로 잘 만들어졌다. 시트러스와 바닐라의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 자주 마시고 싶은 일상형 위스키로서 강력히 추천한다.", 4, NOW(), 126, 170);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 최고의 경험이다! 이렇게 좋은 위스키는 처음이다. 정교한 향신료의 뉘앙스가 세련되게 표현된다. 충분히 좋은 선택이 될 것 같다.", 5, NOW(), 181, 170);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 좋은 위스키다. 만족도가 정말 높다! 바닐라 향이 매력적이어서 계속 생각난다. 다시 한 번 마셔보고 싶은 생각이 드는 위스키다.", 4, NOW(), 207, 170);
