INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "좋은 위스키이지만 몇 가지 개선 여지가 있어 보인다. 곡물와 시트러스의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 자주 마시고 싶은 일상형 위스키로서 강력히 추천한다.", 4, NOW(), 427, 176);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "여러 가지 문제점이 보인다. 개선이 필요하다. 시나몬의 섬세하고 정교한 표현이 참으로 인상깊다. 시트러스 특성이 개인의 미각 선호도와는 맞지 않아서 아쉽다. 아쉽게도 재구매할 마음이 생기지 않는다.", 2, NOW(), 459, 176);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 훌륭한 위스키다! 충동구매해도 후회 안 한다. 조화로운 프로필이 특징이다. 한 번쯤은 꼭 마셔볼 만한 가치가 있다.", 4, NOW(), 462, 176);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "흥미로운 위스키이지만 완성도는 아쉽다. 고민되는 부분이 있다. 시나몬의 섬세하고 정교한 표현이 참으로 인상깊다. 특별한 매력을 느끼지는 못했지만 나쁘지는 않다. 추천할 만한 가치가 있다.", 3, NOW(), 473, 176);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "무난하고 괜찮은 위스키다. 장단점이 섞여 있다. 특히 시나몬와 곡물 향미가 정말 좋아서 자꾸만 향을 맡게 된다. 다음에 기회가 되면 또 마셔보고 싶은 위스키다. 정말 마음에 든다.", 3, NOW(), 476, 176);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "좋은 위스키이지만 몇 가지 개선 여지가 있어 보인다. 건과일와 숙성 오크의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 자주 마시고 싶은 일상형 위스키로서 강력히 추천한다.", 4, NOW(), 172, 177);
