INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "무난하고 괜찮은 위스키다. 장단점이 섞여 있다. 꿀와 바닐라의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 바나나 향이 조금 강한 편이어서 아쉽다는 느낌이 든다. 다음에 기회가 되면 또 마셔보고 싶은 위스키다.", 3, NOW(), 435, 181);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "매우 잘 완성된 위스키다. 완성도 면에서 높은 수준이다. 캐러멜의 섬세하고 정교한 표현이 참으로 인상깊다. 자주 마시고 싶은 일상형 위스키로서 강력히 추천한다. 추천할 만한 가치가 있다.", 4, NOW(), 471, 181);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "무난하고 괜찮은 위스키다. 장단점이 섞여 있다. 특히 시나몬와 캐러멜 향미가 정말 좋아서 자꾸만 향을 맡게 된다. 바나나 향이 조금 강한 편이어서 아쉽다는 느낌이 든다. 다음에 기회가 되면 또 마셔보고 싶은 위스키다.", 3, NOW(), 12, 182);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 맛있어서 자꾸 마시고 싶은 위스키다! 특히 바나나와 시트러스 향미가 정말 좋아서 자꾸만 향을 맡게 된다. 위스키 애호가라면 반드시 한 번 마셔봐야 할 가치 있는 위스키다. 정말 마음에 든다.", 5, NOW(), 51, 182);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "무난하고 괜찮은 위스키다. 장단점이 섞여 있다. 특히 바나나와 시나몬 향미가 정말 좋아서 자꾸만 향을 맡게 된다. 다음에 기회가 되면 또 마셔보고 싶은 위스키다.", 3, NOW(), 97, 182);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 좋은 위스키다. 만족도가 정말 높다! 초콜릿의 섬세하고 정교한 표현이 참으로 인상깊다. 다시 한 번 마셔보고 싶은 생각이 드는 위스키다.", 4, NOW(), 112, 182);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 맛있어서 자꾸 마시고 싶은 위스키다! 초콜릿의 섬세하고 정교한 표현이 참으로 인상깊다. 위스키 애호가라면 반드시 한 번 마셔봐야 할 가치 있는 위스키다. 추천할 만한 가치가 있다.", 5, NOW(), 141, 182);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "무난하고 괜찮은 위스키다. 장단점이 섞여 있다. 부드러운 식감 속에 진한 달콤함이 천천히 펼쳐지는 경험이 정말 좋다. 다음에 기회가 되면 또 마셔보고 싶은 위스키다.", 3, NOW(), 200, 182);
