INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "무난하고 괜찮은 위스키다. 장단점이 섞여 있다. 시나몬와 숙성 오크의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 다음에 기회가 되면 또 마셔보고 싶은 위스키다.", 3, NOW(), 66, 188);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "평범한 수준의 위스키다. 특별한 매력이 부족하다. 시나몬와 건과일의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 특별한 매력을 느끼지는 못했지만 나쁘지는 않다.", 3, NOW(), 71, 188);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "우수한 완성도의 위스키라고 평가한다. 시나몬와 새 오크의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 모든 위스키 애호가에게 강력 추천하고 싶은 제품이다! 추천할 만한 가치가 있다.", 5, NOW(), 106, 188);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 맛있어서 자꾸 마시고 싶은 위스키다! 시나몬의 섬세하고 정교한 표현이 참으로 인상깊다. 위스키 애호가라면 반드시 한 번 마셔봐야 할 가치 있는 위스키다. 추천할 만한 가치가 있다.", 5, NOW(), 107, 188);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 좋은 위스키다. 만족도가 정말 높다! 우아한 달콤함과 풍성한 바디감의 조화로운 상호작용이 돋보인다. 다시 한 번 마셔보고 싶은 생각이 드는 위스키다.", 4, NOW(), 112, 188);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 훌륭한 위스키다! 충동구매해도 후회 안 한다. 캐러멜와 시나몬의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 다만 새 오크 때문에 사람에 따라 호불호가 나뉠 수 있을 것 같다. 다시 한 번 마셔보고 싶은 생각이 드는 위스키다.", 4, NOW(), 124, 188);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "무난하고 괜찮은 위스키다. 장단점이 섞여 있다. 특히 숙성 오크와 새 오크 향미가 정말 좋아서 자꾸만 향을 맡게 된다. 다음에 기회가 되면 또 마셔보고 싶은 위스키다. 정말 마음에 든다.", 3, NOW(), 143, 188);
