INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "무난하고 괜찮은 위스키다. 장단점이 섞여 있다. 정교한 향신료의 뉘앙스가 세련되게 표현된다. 다음에 기회가 되면 또 마셔보고 싶은 위스키다. 추천할 만한 가치가 있다.", 3, NOW(), 422, 204);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "흥미로운 위스키이지만 완성도는 아쉽다. 고민되는 부분이 있다. 정교한 향신료의 뉘앙스가 세련되게 표현된다. 곡물 향이 조금 강한 편이어서 아쉽다는 느낌이 든다. 특별한 매력을 느끼지는 못했지만 나쁘지는 않다.", 3, NOW(), 426, 204);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 좋은 위스키다. 만족도가 정말 높다! 따뜻하고 부드러운 향신료 향이 입맛을 돋운다. 한 번쯤은 꼭 마셔볼 만한 가치가 있다.", 4, NOW(), 432, 204);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 훌륭한 위스키다! 충동구매해도 후회 안 한다. 피트의 섬세하고 정교한 표현이 참으로 인상깊다. 다시 한 번 마셔보고 싶은 생각이 드는 위스키다.", 4, NOW(), 462, 204);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 맛있어서 자꾸 마시고 싶은 위스키다! 사과/배와 후추의 균형감이 뛰어나고, 이들의 복합적인 상호작용이 매우 인상적이다. 위스키 애호가라면 반드시 한 번 마셔봐야 할 가치 있는 위스키다.", 5, NOW(), 91, 205);
