INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "무난하고 괜찮은 위스키다. 장단점이 섞여 있다. 이탄 향의 복합미와 깊이감이 매력적으로 표현된다. 다음에 기회가 되면 또 마셔보고 싶은 위스키다. 추천할 만한 가치가 있다.", 3, NOW(), 373, 213);
