INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 최고의 경험이다! 이렇게 좋은 위스키는 처음이다. 새 오크의 섬세하고 정교한 표현이 참으로 인상깊다. 위스키 애호가라면 반드시 한 번 마셔봐야 할 가치 있는 위스키다. 추천할 만한 가치가 있다.", 5, NOW(), 265, 215);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 좋은 위스키다. 만족도가 정말 높다! 바다/소금 향이 매력적이어서 계속 생각난다. 다시 한 번 마셔보고 싶은 생각이 드는 위스키다.", 4, NOW(), 295, 215);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "정말 최고의 경험이다! 이렇게 좋은 위스키는 처음이다. 이탄 향의 복합미와 깊이감이 매력적으로 표현된다. 충분히 좋은 선택이 될 것 같다.", 5, NOW(), 363, 215);
INSERT INTO reviews (attached_note_id, created_at, public_text, rating, updated_at, user_id, whiskey_id) VALUES (NULL, NOW(), "나쁘지 않은 위스키다. 충분히 마실 만하다. 은은하고 향긋한 피트 향이 이 위스키의 정체성을 잘 드러낸다. 다음에 기회가 되면 또 마셔보고 싶은 위스키다.", 3, NOW(), 379, 215);
