INSERT INTO tasting_notes (id, user_id, whiskey_id, body_score, finish_score, smoky_score, spicy_score, sweet_score, memo, is_draft, created_at, updated_at) VALUES (18, 145, 96, 6, 5, 2, 4, 6, '향: 바닐라의 섬세한 표현, 사과·배의 신선함, 꽃 향이 어우러진다. 달콤함이 중심을 이루며 \n맛: 곡물 향, 사과·배의 신선함, 오크 향이 구조를 이룬다. 특히 균형, 복합 측면에서 뛰어나다. \n여운: 중간 지속된다. 따뜻함이 조용히 남는다.', 0, NOW(), NOW());
