INSERT INTO tasting_notes (id, user_id, whiskey_id, body_score, finish_score, smoky_score, spicy_score, sweet_score, memo, is_draft, created_at, updated_at) VALUES (124, 386, 90, 9, 10, 2, 4, 7, '향: 건과일의 깊이, 초콜릿의 풍부함, 가죽의 깊이이 어우러진다. 달콤함이 중심을 이루며 \n맛: 향신료의 따뜻함, 건과일의 깊이, 오래된 나무의 온기이 구조를 이룬다. 특히 균형, 복합 측면에서 뛰어나다. \n여운: 길고 지속된다. 따뜻함이 조용히 남는다.', 0, NOW(), NOW());
