INSERT INTO tasting_notes (id, user_id, whiskey_id, body_score, finish_score, smoky_score, spicy_score, sweet_score, memo, is_draft, created_at, updated_at) VALUES (353, 227, 124, 6, 7, 2, 5, 6, '바닐라 향이 올라오고, 캐러멜 향이 따라온다. 조금 아쉽긴 한데. 여운도 길게 남는다.', 0, NOW(), NOW());
INSERT INTO tasting_notes (id, user_id, whiskey_id, body_score, finish_score, smoky_score, spicy_score, sweet_score, memo, is_draft, created_at, updated_at) VALUES (354, 337, 124, 7, 7, 2, 4, 7, '향: 바닐라의 섬세한 표현, 꿀 향, 과일 향이 어우러진다. 달콤함이 중심을 이루며 \n맛: 캐러멜 향, 향신료 향, 신선한 오크의 나무향이 구조를 이룬다. 특히 균형, 복합 측면에서 뛰어나다. \n여운: 길고 지속된다. 따뜻함이 조용히 남는다.', 0, NOW(), NOW());
