INSERT INTO tasting_notes (id, user_id, whiskey_id, body_score, finish_score, smoky_score, spicy_score, sweet_score, memo, is_draft, created_at, updated_at) VALUES (525, 413, 194, 5, 5, 1, 5, 6, '향: 바닐라 향, 캐러멜 향, 곡물 향이 어우러진다. 달콤함이 중심을 이루며 \n맛: 바닐라 향, 캐러멜 향, 오크 향이 구조를 이룬다. 특히 조화 측면에서 뛰어나다. \n여운: 중간 지속된다. 따뜻함이 조용히 남는다.', 0, NOW(), NOW());
INSERT INTO tasting_notes (id, user_id, whiskey_id, body_score, finish_score, smoky_score, spicy_score, sweet_score, memo, is_draft, created_at, updated_at) VALUES (526, 465, 194, 4, 4, 1, 4, 6, '향: 바닐라 향, 캐러멜 향, 곡물 향이 어우러진다. 달콤함이 중심을 이루며 \n맛: 바닐라 향, 캐러멜 향, 오크 향이 구조를 이룬다. 특히 조화 측면에서 뛰어나다. \n여운: 중간 지속된다. 따뜻함이 조용히 남는다.', 0, NOW(), NOW());
INSERT INTO tasting_notes (id, user_id, whiskey_id, body_score, finish_score, smoky_score, spicy_score, sweet_score, memo, is_draft, created_at, updated_at) VALUES (527, 491, 194, 4, 5, 1, 5, 6, '바닐라 향이 올라오고, 바닐라 향이 따라온다. 좋네. 여운은 깔끔하다.', 0, NOW(), NOW());
INSERT INTO tasting_notes (id, user_id, whiskey_id, body_score, finish_score, smoky_score, spicy_score, sweet_score, memo, is_draft, created_at, updated_at) VALUES (528, 46, 4, 7, 8, 4, 5, 6, '피트 향이 올라오고, 향신료 향이 따라온다. 좋네. 여운도 길게 남는다.', 0, NOW(), NOW());
INSERT INTO tasting_notes (id, user_id, whiskey_id, body_score, finish_score, smoky_score, spicy_score, sweet_score, memo, is_draft, created_at, updated_at) VALUES (529, 104, 4, 8, 9, 3, 5, 7, '향: 피트 향, 오래된 오크 향, 꽃 향이 어우러진다. 달콤함이 중심을 이루며 \n맛: 향신료 향, 건과일의 깊이, 초콜릿의 풍부함이 구조를 이룬다. 특히 균형, 복합 측면에서 뛰어나다. \n여운: 길고 지속된다. 따뜻함이 조용히 남는다.', 0, NOW(), NOW());
INSERT INTO tasting_notes (id, user_id, whiskey_id, body_score, finish_score, smoky_score, spicy_score, sweet_score, memo, is_draft, created_at, updated_at) VALUES (530, 209, 4, 7, 8, 4, 4, 7, '향: 피트 향이 강함이 올라온다. 그 뒤로 오래된 나무 향이 강함이 따라온다. \n맛: 향신료의 따뜻함이 중심을 잡는다. 건과일 향이 어우러진다. 특히 균형 부분이 좋다. \n여운: 길게 남는다.', 0, NOW(), NOW());
INSERT INTO tasting_notes (id, user_id, whiskey_id, body_score, finish_score, smoky_score, spicy_score, sweet_score, memo, is_draft, created_at, updated_at) VALUES (531, 279, 4, 8, 8, 4, 5, 6, '향: 피트 향이 올라온다. 그 뒤로 꽃 향이 따라온다. \n맛: 향신료 향이 중심을 잡는다. Orange이 어우러진다. \n여운: 길게 남는다.', 0, NOW(), NOW());
