INSERT INTO tasting_notes (id, user_id, whiskey_id, body_score, finish_score, smoky_score, spicy_score, sweet_score, memo, is_draft, created_at, updated_at) VALUES (929, 312, 212, 7, 6, 5, 6, 6, '향: 피트 향이 강함, 건과일 향, 소금기 있는 향이 어우러진다. 달콤함이 중심을 이루며 스모키함이 정제되게 표현된다. \n맛: 피트 향이 강함, 캐러멜이 강함, Dark Berry이 구조를 이룬다. 특히 균형, 복합 측면에서 뛰어나다. \n여운: 길고 지속된다. 스모키함이 우아하게 사그라진다.', 0, NOW(), NOW());
