INSERT INTO tasting_notes (id, user_id, whiskey_id, body_score, finish_score, smoky_score, spicy_score, sweet_score, memo, is_draft, created_at, updated_at) VALUES (1058, 417, 67, 6, 8, 8, 6, 5, '향: 피트 향이 올라온다. 그 뒤로 약간의 의약적 향이 따라온다. \n맛: 바닐라 향이 중심을 잡는다. 피트 향이 어우러진다. 특히 복합 부분이 좋다. \n여운: 길게 남는다.', 0, NOW(), NOW());
