INSERT INTO tasting_notes (id, user_id, whiskey_id, body_score, finish_score, smoky_score, spicy_score, sweet_score, memo, is_draft, created_at, updated_at) VALUES (1092, 340, 76, 6, 6, 2, 5, 6, '향: 향신료의 따뜻함이 올라온다. 그 뒤로 건과일 향이 따라온다. \n맛: 오크 향이 중심을 잡는다. 건과일 향이 어우러진다. 특히 균형 부분이 좋다. \n여운: 길게 남는다.', 0, NOW(), NOW());
