INSERT INTO tasting_notes (id, user_id, whiskey_id, body_score, finish_score, smoky_score, spicy_score, sweet_score, memo, is_draft, created_at, updated_at) VALUES (1098, 86, 15, 7, 7, 3, 5, 5, '향: 피트 향, 소금기 있는 향, 사과·배의 신선함이 어우러진다. \n맛: 곡물의 고소함, 피트 향, 소금기 있는 향이 구조를 이룬다. 특히 균형, 복합 측면에서 뛰어나다. \n여운: 길고 지속된다. 따뜻함이 조용히 남는다.', 0, NOW(), NOW());
INSERT INTO tasting_notes (id, user_id, whiskey_id, body_score, finish_score, smoky_score, spicy_score, sweet_score, memo, is_draft, created_at, updated_at) VALUES (1099, 112, 15, 7, 7, 4, 4, 5, '향: 피트 향이 올라온다. 그 뒤로 해안 바람의 미네랄감이 따라온다. \n맛: 곡물 향이 중심을 잡는다. 피트 향이 어우러진다. \n여운: 길게 남는다.', 0, NOW(), NOW());
INSERT INTO tasting_notes (id, user_id, whiskey_id, body_score, finish_score, smoky_score, spicy_score, sweet_score, memo, is_draft, created_at, updated_at) VALUES (1100, 124, 15, 7, 8, 3, 5, 5, '향: 피트 향이 올라온다. 그 뒤로 소금기 있는 향이 따라온다. \n맛: 곡물 향이 중심을 잡는다. 피트 향이 어우러진다. 특히 우아 부분이 좋다. \n여운: 길게 남는다.', 0, NOW(), NOW());
INSERT INTO tasting_notes (id, user_id, whiskey_id, body_score, finish_score, smoky_score, spicy_score, sweet_score, memo, is_draft, created_at, updated_at) VALUES (1101, 157, 15, 7, 7, 4, 5, 5, '향: 피트 스모크의 우아한 표현, 해안 바람의 미네랄감, 시트러스 향이 어우러진다. 스모키함이 정제되게 표현된다. \n맛: 곡물이 거슬림, 피트 스모크의 우아한 표현, 해안 바람의 미네랄감이 구조를 이룬다. 특히 균형, 복합 측면에서 뛰어나다. \n여운: 길고 지속된다. 스모키함이 우아하게 사그라진다.', 0, NOW(), NOW());
