INSERT INTO tasting_notes (id, user_id, whiskey_id, body_score, finish_score, smoky_score, spicy_score, sweet_score, memo, is_draft, created_at, updated_at) VALUES (1230, 474, 193, 7, 7, 2, 6, 5, '곡물 향이 올라오고, 캐러멜 향이 따라온다. 나쁘지 않아. 여운도 길게 남는다.', 0, NOW(), NOW());
