INSERT INTO tasting_notes (id, user_id, whiskey_id, body_score, finish_score, smoky_score, spicy_score, sweet_score, memo, is_draft, created_at, updated_at) VALUES (1662, 325, 162, 5, 5, 2, 5, 6, '향: 향신료 향, 후추 맛, 시트러스 향이 어우러진다. 달콤함이 중심을 이루며 \n맛: 허브 향, 후추 맛, 오크 향이 구조를 이룬다. \n여운: 중간 지속된다. 따뜻함이 조용히 남는다.', 0, NOW(), NOW());
INSERT INTO tasting_notes (id, user_id, whiskey_id, body_score, finish_score, smoky_score, spicy_score, sweet_score, memo, is_draft, created_at, updated_at) VALUES (1663, 394, 162, 6, 6, 2, 6, 6, '향: 향신료의 따뜻함, 후추 맛, 시트러스가 거슬림이 어우러진다. 달콤함이 중심을 이루며 \n맛: 허브 향, 후추 맛, 오크 향이 구조를 이룬다. 특히 균형, 복합 측면에서 뛰어나다. \n여운: 길고 지속된다. 따뜻함이 조용히 남는다.', 0, NOW(), NOW());
INSERT INTO tasting_notes (id, user_id, whiskey_id, body_score, finish_score, smoky_score, spicy_score, sweet_score, memo, is_draft, created_at, updated_at) VALUES (1664, 434, 162, 5, 5, 1, 5, 6, '향신료 향이 올라오고, 허브 향이 따라온다. 나쁘지 않아. 여운은 깔끔하다.', 0, NOW(), NOW());
INSERT INTO tasting_notes (id, user_id, whiskey_id, body_score, finish_score, smoky_score, spicy_score, sweet_score, memo, is_draft, created_at, updated_at) VALUES (1665, 453, 162, 6, 6, 2, 6, 5, '향신료 향이 올라오고, 허브 향이 따라온다. 좋네. 여운도 길게 남는다.', 0, NOW(), NOW());
INSERT INTO tasting_notes (id, user_id, whiskey_id, body_score, finish_score, smoky_score, spicy_score, sweet_score, memo, is_draft, created_at, updated_at) VALUES (1666, 104, 9, 7, 7, 5, 5, 5, '향: 피트 향, 꿀 향, 장작 향이 어우러진다. 스모키함이 정제되게 표현된다. \n맛: 곡물이 거슬림, 피트 향, 후추 맛이 구조를 이룬다. 특히 복합, 깊이 측면에서 뛰어나다. \n여운: 길고 지속된다. 스모키함이 우아하게 사그라진다.', 0, NOW(), NOW());
