INSERT INTO tasting_notes (id, user_id, whiskey_id, body_score, finish_score, smoky_score, spicy_score, sweet_score, memo, is_draft, created_at, updated_at) VALUES (1833, 91, 205, 5, 6, 4, 5, 5, '향: 바닐라 향이 올라온다. 그 뒤로 캐러멜 향이 따라온다. \n맛: 곡물 향이 중심을 잡는다. 바닐라 향이 어우러진다. 특히 균형 부분이 좋다. \n여운: 길게 남는다.', 0, NOW(), NOW());
INSERT INTO tasting_notes (id, user_id, whiskey_id, body_score, finish_score, smoky_score, spicy_score, sweet_score, memo, is_draft, created_at, updated_at) VALUES (1834, 153, 205, 5, 5, 4, 5, 6, '향: 바닐라 향이 올라온다. 그 뒤로 캐러멜 향이 따라온다. \n맛: 곡물 향이 중심을 잡는다. 바닐라 향이 어우러진다. 특히 조화 부분이 좋다. \n여운: 깔끔하게 남는다.', 0, NOW(), NOW());
INSERT INTO tasting_notes (id, user_id, whiskey_id, body_score, finish_score, smoky_score, spicy_score, sweet_score, memo, is_draft, created_at, updated_at) VALUES (1835, 157, 205, 6, 6, 5, 5, 5, '향: 바닐라 향, 캐러멜 향, 과일 향이 어우러진다. 스모키함이 정제되게 표현된다. \n맛: 곡물이 거슬림, 바닐라 향, 캐러멜 향이 구조를 이룬다. \n여운: 길고 지속된다. 스모키함이 우아하게 사그라진다.', 0, NOW(), NOW());
INSERT INTO tasting_notes (id, user_id, whiskey_id, body_score, finish_score, smoky_score, spicy_score, sweet_score, memo, is_draft, created_at, updated_at) VALUES (1836, 184, 205, 6, 6, 4, 5, 6, '향: 바닐라 향, 캐러멜의 풍부함, 과일 향이 어우러진다. 달콤함이 중심을 이루며 스모키함이 정제되게 표현된다. \n맛: 곡물 향, 바닐라 향, 캐러멜의 풍부함이 구조를 이룬다. \n여운: 길고 지속된다. 스모키함이 우아하게 사그라진다.', 0, NOW(), NOW());
INSERT INTO tasting_notes (id, user_id, whiskey_id, body_score, finish_score, smoky_score, spicy_score, sweet_score, memo, is_draft, created_at, updated_at) VALUES (1837, 244, 205, 5, 6, 3, 5, 6, '향: 바닐라 향이 올라온다. 그 뒤로 캐러멜의 풍부함이 따라온다. \n맛: 곡물 향이 중심을 잡는다. 바닐라 향이 어우러진다. 특히 균형 부분이 좋다. \n여운: 길게 남는다.', 0, NOW(), NOW());
INSERT INTO tasting_notes (id, user_id, whiskey_id, body_score, finish_score, smoky_score, spicy_score, sweet_score, memo, is_draft, created_at, updated_at) VALUES (1838, 493, 205, 6, 6, 4, 5, 6, '바닐라 향이 올라오고, 곡물 향이 따라온다. 나쁘지 않아. 여운도 길게 남는다.', 0, NOW(), NOW());
INSERT INTO tasting_notes (id, user_id, whiskey_id, body_score, finish_score, smoky_score, spicy_score, sweet_score, memo, is_draft, created_at, updated_at) VALUES (1839, 87, 10, 8, 8, 3, 5, 7, '바닐라 향이 올라오고, 오크 향이 따라온다. 좋네. 여운도 길게 남는다.', 0, NOW(), NOW());
INSERT INTO tasting_notes (id, user_id, whiskey_id, body_score, finish_score, smoky_score, spicy_score, sweet_score, memo, is_draft, created_at, updated_at) VALUES (1840, 174, 10, 7, 8, 4, 5, 6, '향: 바닐라 향, 피트 향, 꿀 향이 어우러진다. 달콤함이 중심을 이루며 스모키함이 정제되게 표현된다. \n맛: 신선한 오크의 나무향, 건과일 향, 향신료 향이 구조를 이룬다. 특히 균형, 복합 측면에서 뛰어나다. \n여운: 길고 지속된다. 스모키함이 우아하게 사그라진다.', 0, NOW(), NOW());
